function makeVariants(storages, colors, basePrice) {
  const out = [];
  storages.forEach((s, tierIndex) => {
    colors.forEach((c) => {
      out.push({
        storage: s,
        color: c,
        sellingPrice: basePrice ? basePrice + tierIndex * 45 : null,
      });
    });
  });
  return out;
}

