// Listing order for a stakeholder demo: lead with the richest, most fully-
// populated product (Samsung Galaxy S26 Ultra - 3 real storage/color
// variants, per-variant photos) so the very first thing shown is the ideal
// case, not whatever happened to be first in the data file. Everything
// else is shuffled once per page load (not on every re-render, and not
// re-shuffled by search/filter interactions) so Samsung doesn't otherwise
// dominate the top of the list.
const HERO_PRODUCT_ID = "p1b";
const DISPLAY_PRODUCTS = (() => {
  const hero = PRODUCTS.find((p) => p.id === HERO_PRODUCT_ID);
  const rest = PRODUCTS.filter((p) => p.id !== HERO_PRODUCT_ID);
  for (let i = rest.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [rest[i], rest[j]] = [rest[j], rest[i]];
  }
  return hero ? [hero, ...rest] : rest;
})();

