// Compact covers both mobile and tablet - tablet reuses the mobile PLP
// pattern (card grid + full-screen detail) rather than a third layout.
function useIsCompact() {
  const [isCompact, setIsCompact] = useState(
    () => typeof window !== "undefined" && window.innerWidth < 1024
  );
  useEffect(() => {
    // Recompute from window.innerWidth directly rather than trusting the
    // matchMedia event's own e.matches - programmatic viewport overrides
    // (devtools device toolbar, automated previews, CDP-driven resizes)
    // don't always fire a clean matchMedia "change" event, but they do
    // fire "resize". Listening to both and recalculating from innerWidth
    // each time covers both event pipelines instead of trusting one.
    const check = () => setIsCompact(window.innerWidth < 1024);
    check();
    window.addEventListener("resize", check);
    const mql = window.matchMedia("(max-width: 1023px)");
    mql.addEventListener("change", check);
    return () => {
      window.removeEventListener("resize", check);
      mql.removeEventListener("change", check);
    };
  }, []);
  return isCompact;
}

// Measures a DOM node's rendered height and keeps it in sync via
// ResizeObserver, so layout (like the mobile footer's variable height when
// the tray bar appears/disappears) is measured from what's actually
// rendered rather than a guessed/hardcoded pixel value.
function useElementHeight(active) {
  const ref = useRef(null);
  const [height, setHeight] = useState(0);
  useEffect(() => {
    if (!active || !ref.current) return;
    const el = ref.current;
    const update = () => setHeight(el.offsetHeight);
    update();
    const ro = new ResizeObserver(update);
    ro.observe(el);
    return () => ro.disconnect();
  }, [active]);
  return [ref, height];
}

// Scrolls a card into view inside a scroll container, accounting for a
// fixed-position footer that overlaps the container's bottom edge (which
// native scrollIntoView doesn't know about, since the footer isn't part of
// the container's own box/overflow clipping).
function scrollCardIntoView(cardEl, containerEl, footerHeight) {
  if (!cardEl || !containerEl) return;
  const cardRect = cardEl.getBoundingClientRect();
  const containerRect = containerEl.getBoundingClientRect();
  const visibleBottom = containerRect.bottom - footerHeight;
  const margin = 16;
  if (cardRect.bottom > visibleBottom) {
    containerEl.scrollTo({ top: containerEl.scrollTop + (cardRect.bottom - visibleBottom) + margin, behavior: "smooth" });
  } else if (cardRect.top < containerRect.top) {
    containerEl.scrollTo({ top: containerEl.scrollTop - (containerRect.top - cardRect.top) - margin, behavior: "smooth" });
  }
}

