function NavRail({ active, collapsed, onToggleCollapse, themeDark, onToggleTheme, onSelect }) {
  // Watchlist is mobile/tablet-only - desktop already shows it upfront as
  // the always-visible strip above the workspace, so it doesn't need a
  // nav entry too.
  const items = NAV_ITEMS.filter((it) => it.id !== "watchlist");
  return (
    <div className={"navrail" + (collapsed ? " is-collapsed" : "")}>
      <div className="navrail-top">
        <div className="navrail-mark">
          {collapsed ? <BrandIcon size={30} /> : <BrandLockup height={30} />}
        </div>
      </div>

      <div className="navrail-items">
        {items.map((it) => {
          const Icon = it.icon;
          const isActive = it.id === active;
          return (
            <button
              key={it.id}
              className={"navrail-item" + (isActive ? " is-active" : "")}
              title={collapsed ? it.label : undefined}
              onClick={onSelect ? () => onSelect(it.id) : undefined}
            >
              <Icon size={19} strokeWidth={1.75} />
              {!collapsed && <span className="navrail-label">{it.label}</span>}
              {collapsed && <span className="navrail-tooltip">{it.label}</span>}
            </button>
          );
        })}
      </div>

      {/* Theme switching isn't implemented yet - this only toggles which
          icon shows, as a placeholder for the real dark/light switcher.
          Icon/label show the state a click switches TO, not the current
          state (e.g. while in dark mode, this reads "Light"). */}
      <button
        className="navrail-item navrail-theme-toggle"
        onClick={onToggleTheme}
        title={themeDark ? "Switch to light theme" : "Switch to dark theme"}
      >
        {themeDark ? <Sun size={19} strokeWidth={1.75} /> : <Moon size={19} strokeWidth={1.75} />}
        {!collapsed && <span className="navrail-label">{themeDark ? "Light" : "Dark"}</span>}
        {collapsed && <span className="navrail-tooltip">{themeDark ? "Light theme" : "Dark theme"}</span>}
      </button>

      <button
        className="navrail-toggle"
        onClick={onToggleCollapse}
        title={collapsed ? "Expand sidebar" : "Collapse sidebar"}
      >
        {collapsed ? <ChevronsRight size={15} strokeWidth={1.9} /> : <ChevronsLeft size={15} strokeWidth={1.9} />}
      </button>
    </div>
  );
}

function Ticker({ collapsed, compactLabel }) {
  const items = [...TICKER_ITEMS, ...TICKER_ITEMS];
  return (
    <div className={"ticker" + (collapsed ? " is-collapsed" : "")}>
      <div className="ticker-label">
        <span className="dot" /> {compactLabel ? "LIVE" : "LIVE ACTIVITY"}
      </div>
      <div className="ticker-track-wrap">
        <div className="ticker-track">
          {items.map((t, i) => (
            <span className="ticker-item" key={i}>
              {t}
              <span className="ticker-sep">•</span>
            </span>
          ))}
        </div>
      </div>
    </div>
  );
}

function BrandFilter({ brands, selected, onToggle }) {
  if (brands.length === 0) return null;
  return (
    <div className="brandrow">
      {brands.map((b) => {
        const isActive = selected.includes(b.code);
        return (
          <button
            key={b.code}
            className="brandfilter-btn"
            onClick={() => onToggle(b.code)}
            title={b.name}
          >
            <LogoPlate code={b.code} active={isActive} />
          </button>
        );
      })}
    </div>
  );
}

function CategoryTabs({ categories, selected, onSelect }) {
  return (
    <div className="cattabs">
      {categories.map((c) => {
        const Icon = c.icon;
        const isActive = c.id === selected;
        return (
          <button
            key={c.id}
            className={"cattab" + (isActive ? " is-active" : "")}
            onClick={() => onSelect(c.id)}
          >
            <Icon size={15} strokeWidth={1.8} />
            {c.name}
          </button>
        );
      })}
    </div>
  );
}

function LogoPlate({ code, active, size = "default" }) {
  const b = BRAND_STYLE[code];
  if (!b) return null;
  return (
    <div className={"logoplate logoplate-" + size + (active ? " is-active" : "")}>
      {active && (
        <span className="logoplate-remove-badge">
          <X size={9} strokeWidth={3} />
        </span>
      )}
      {b.logoSrc ? (
        <img src={b.logoSrc} alt={b.label} className="logoplate-img" />
      ) : (
        <span
          className="logoplate-fallback"
          style={{
            color: b.color,
            fontWeight: b.weight,
            letterSpacing: b.tracking,
            fontStyle: b.italic ? "italic" : "normal",
          }}
        >
          {b.label}
        </span>
      )}
    </div>
  );
}

function getCoverImage(product) {
  if (product.image) return product.image;
  const withImage = product.variants.find((v) => v.image);
  return withImage ? withImage.image : null;
}

function productHasStorage(product) {
  return product.variants.some((v) => v.storage && v.storage !== "—");
}

function productHasColor(product) {
  return product.variants.some((v) => v.color && v.color !== "—");
}

// Builds the variant table's grid-template-columns, dropping tracks for
// whichever reference columns don't apply to this product (rather than
// showing them with a dash) - real catalog rows vary: some have no color,
// some no storage, some neither.
function buildVariantGridTemplate(hasStorage, hasColor) {
  // No reference-price track - that price now lives in the header's
  // per-variant price list, so the table is purely for placing bids.
  const cols = [];
  if (hasStorage) cols.push("0.9fr");
  if (hasColor) cols.push("1.2fr");
  cols.push("0.8fr", "1fr", "78px");
  return cols.join(" ");
}

function ProductRow({ product, isActive, onClick, isWatchlisted, onToggleWatchlist }) {
  const Icon = CATEGORY_ICON[product.category] || LayoutGrid;
  const cover = getCoverImage(product);
  const [imgFailed, setImgFailed] = useState(false);
  const showPhoto = cover && !imgFailed;
  // Was a <button> - switched to a div with an explicit button role so a
  // real nested <button> (the star toggle) is valid, instead of nesting
  // interactive controls inside a <button> (invalid HTML, and the star
  // click would also fire row selection via bubbling without a real fix).
  const handleKeyDown = (e) => {
    if (e.key === "Enter" || e.key === " ") {
      e.preventDefault();
      onClick();
    }
  };
  return (
    <div
      className={"prow" + (isActive ? " is-active" : "")}
      role="button"
      tabIndex={0}
      onClick={onClick}
      onKeyDown={handleKeyDown}
    >
      <div className={"prow-thumb" + (showPhoto ? " has-photo" : "")}>
        {showPhoto ? (
          <img src={cover} alt="" className="prow-thumb-img" onError={() => setImgFailed(true)} />
        ) : (
          <Icon size={26} strokeWidth={1.4} />
        )}
      </div>
      <div className="prow-mid">
        <div className="prow-name">{product.name}</div>
        <div className="prow-meta-row">
          <span className="prow-variant-count">
            {product.variants.length} variant{product.variants.length > 1 ? "s" : ""}
          </span>
        </div>
      </div>
      {onToggleWatchlist && (
        <button
          className={"prow-star" + (isWatchlisted ? " is-active" : "")}
          title={isWatchlisted ? "Remove from watchlist" : "Add to watchlist"}
          onClick={(e) => {
            e.stopPropagation();
            onToggleWatchlist(product.id);
          }}
        >
          <Star size={15} strokeWidth={2} fill={isWatchlisted ? "currentColor" : "none"} />
        </button>
      )}
      <ChevronRight size={15} strokeWidth={1.75} className="prow-chevron" />
    </div>
  );
}

// Small stable hash so the activity note shows consistent (not flickering)
// mock numbers per product, without needing a real backend yet.
function hashProductId(id) {
  let h = 0;
  for (let i = 0; i < id.length; i++) h = (h * 31 + id.charCodeAt(i)) >>> 0;
  return h;
}

// Illustrative only, same reasoning as LastBidNote/ActivityNote - there's no
// real price-history backend yet, so this generates a deterministic 12-point
// trend (stable across renders, not random) ending at a given real price,
// plus the direction/delta used to color the price block and sparkline.
// Placeholder pending real pricing history.
function buildTrend(basePrice, key) {
  if (!basePrice) return null;
  const pointCount = 12;
  // Walk backward from the current price using per-step deterministic noise,
  // then reverse - keeps the trend end pinned to the real reference price.
  const steps = [];
  let price = basePrice;
  for (let i = 0; i < pointCount - 1; i++) {
    const stepHash = hashProductId(key + "-" + i);
    const pct = ((stepHash % 13) - 6) / 100; // -6%..+6% per step
    price = Math.max(1, price / (1 + pct));
    steps.push(Math.round(price));
  }
  const trend = [...steps.reverse(), Math.round(basePrice)];
  const first = trend[0];
  const last = trend[trend.length - 1];
  const change = last - first;
  const changePct = first ? (change / first) * 100 : 0;
  const direction = change > 0 ? "up" : change < 0 ? "down" : "flat";
  return { trend, current: last, change, changePct, direction };
}

// Independent per-variant trend - different variants can genuinely move on
// their own (demand, stock, negotiated pricing), so each price row gets its
// own real direction/color rather than repeating the collective one.
function getVariantPriceTrend(product, variant) {
  if (!variant.sellingPrice) return null;
  const key = product.id + "-" + variant.storage + "-" + variant.color + "-varTrend";
  return buildTrend(variant.sellingPrice, key);
}

// Collective trend for the product overall - drives the sparkline and the
// one aggregate delta shown beside it. Derived by averaging the actual
// per-variant trends point-by-point, not an independently-generated mock -
// generating it separately let the aggregate contradict the rows below it
// (e.g. every variant trending up while the "average" claimed down), since
// nothing tied the two together.
function getPriceTrend(product) {
  const variantTrends = product.variants.map((v) => getVariantPriceTrend(product, v)).filter(Boolean);
  if (variantTrends.length === 0) return null;
  const pointCount = variantTrends[0].trend.length;
  const trend = Array.from({ length: pointCount }, (_, i) =>
    Math.round(variantTrends.reduce((sum, vt) => sum + vt.trend[i], 0) / variantTrends.length)
  );
  const first = trend[0];
  const last = trend[trend.length - 1];
  const change = last - first;
  const changePct = first ? (change / first) * 100 : 0;
  const direction = change > 0 ? "up" : change < 0 ? "down" : "flat";
  return { trend, current: last, change, changePct, direction };
}

// Illustrative only, same reasoning as getPriceTrend - the brief asks the
// Watchlist to show stock availability, but there's no real inventory field
// on PRODUCTS yet. Deterministic mock, not a new brand color: "in" reuses
// --green (positive), "out" reuses --red (negative/unavailable), "low" stays
// neutral text rather than inventing a warning color the design system
// doesn't have.
function getStockStatus(product) {
  const roll = hashProductId(product.id + "-stock") % 100;
  if (roll < 8) return "out";
  if (roll < 28) return "low";
  return "in";
}

// Pure trend line, no axis/dates per the brief - a hover crosshair is the
// only way to read a specific point, via relative "N of 12" position since
// there's no real timestamp per point yet.
function Sparkline({ trend, direction }) {
  const width = 140;
  const height = 36;
  const pad = 3;
  const [hoverIndex, setHoverIndex] = useState(null);
  const svgRef = useRef(null);

  const min = Math.min(...trend);
  const max = Math.max(...trend);
  const range = max - min || 1;
  const points = trend.map((v, i) => {
    const x = pad + (i / (trend.length - 1)) * (width - pad * 2);
    const y = pad + (1 - (v - min) / range) * (height - pad * 2);
    return [x, y];
  });
  const pathD = points.map((p, i) => (i === 0 ? `M${p[0]},${p[1]}` : `L${p[0]},${p[1]}`)).join(" ");
  const areaD = `${pathD} L${points[points.length - 1][0]},${height} L${points[0][0]},${height} Z`;
  // Lower price is the favorable outcome for a buyer, so this intentionally
  // inverts the stock-market up=green convention: down=green, up=red.
  const colorVar = direction === "down" ? "var(--green)" : "var(--red)";
  const last = points[points.length - 1];

  const handleMove = (e) => {
    const rect = svgRef.current.getBoundingClientRect();
    const relX = ((e.clientX - rect.left) / rect.width) * width;
    let closest = 0;
    let closestDist = Infinity;
    points.forEach((p, i) => {
      const d = Math.abs(p[0] - relX);
      if (d < closestDist) {
        closestDist = d;
        closest = i;
      }
    });
    setHoverIndex(closest);
  };

  const hovered = hoverIndex !== null ? points[hoverIndex] : null;

  return (
    <div className="sparkline-wrap">
      <svg
        ref={svgRef}
        viewBox={`0 0 ${width} ${height}`}
        width={width}
        height={height}
        className="sparkline-svg"
        onMouseMove={handleMove}
        onMouseLeave={() => setHoverIndex(null)}
      >
        <path d={areaD} fill={colorVar} opacity="0.08" stroke="none" />
        <path d={pathD} fill="none" stroke={colorVar} strokeWidth="1.5" strokeLinejoin="round" strokeLinecap="round" />
        <circle cx={last[0]} cy={last[1]} r="2.5" fill={colorVar} />
        {hovered && (
          <>
            <line x1={hovered[0]} y1={pad} x2={hovered[0]} y2={height - pad} stroke="var(--text-faint)" strokeWidth="1" strokeDasharray="2,2" />
            <circle cx={hovered[0]} cy={hovered[1]} r="2.5" fill="var(--text)" />
          </>
        )}
      </svg>
      {hovered && hoverIndex !== null && (
        <div
          className="sparkline-tooltip"
          style={{ left: `${(hovered[0] / width) * 100}%` }}
        >
          <span className="tabular">${trend[hoverIndex].toLocaleString()}</span>
          <span className="sparkline-tooltip-sub">
            {hoverIndex === trend.length - 1 ? "now" : `${trend.length - 1 - hoverIndex} periods ago`}
          </span>
        </div>
      )}
    </div>
  );
}

// staticSignal: renders one signal (priority: Hot cake > bids in review >
// last bid) with no rotation/timer/remount. Used in the product grid, where
// having many cards independently cross-fade+shift on their own 4s timers
// reads as the grid "jumping" - that pattern only works for a single,
// focused card (the detail page), not a dense grid of many simultaneous
// tiles. Rotation is still used there via the default (non-static) mode.
function ActivityNote({ product, staticSignal }) {
  const signals = [];

  // Bids in review - ~65% of products
  const hBids = hashProductId(product.id + "-actbids");
  if (hBids % 100 < 65) {
    const bidsInReview = 1 + (hBids % 6);
    signals.push({
      key: "bids",
      text: `${bidsInReview} bid${bidsInReview > 1 ? "s" : ""} in review`,
      flame: false,
    });
  }

  // Last bid recency - ~55% of products
  const hLast = hashProductId(product.id + "-actlast");
  if (hLast % 100 < 55) {
    const hoursAgo = 1 + (hLast % 47);
    const timeStr = hoursAgo >= 24 ? `${Math.floor(hoursAgo / 24)}d ago` : `${hoursAgo}h ago`;
    signals.push({ key: "lastbid", text: `Last bid ${timeStr}`, flame: false });
  }

  // Hot cake - high-demand designation, rarer - ~20% of products
  const hHot = hashProductId(product.id + "-acthot");
  if (hHot % 100 < 20) {
    signals.push({ key: "hotcake", text: "Hot cake — high demand", flame: true });
  }

  const [index, setIndex] = useState(0);
  useEffect(() => {
    setIndex(0);
  }, [product.id]);
  useEffect(() => {
    if (staticSignal || signals.length <= 1) return;
    const id = setInterval(() => setIndex((i) => (i + 1) % signals.length), 4000);
    return () => clearInterval(id);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [signals.length, product.id, staticSignal]);

  if (signals.length === 0) return null;

  const current = staticSignal
    ? signals.find((s) => s.key === "hotcake") || signals.find((s) => s.key === "bids") || signals[0]
    : signals[index % signals.length];

  return (
    <div className="activity-note" key={staticSignal ? undefined : current.key}>
      {current.flame ? <Flame size={13} strokeWidth={2} className="activity-flame" /> : <span className="activity-dot" />}
      {current.text}
    </div>
  );
}

// Illustrative only - mocks the buyer's own most recent bid on this product so
// this flow can be reviewed before My Bids / real bid history exists. Uses a
// stable per-product hash so it doesn't flicker, and deliberately only shows
// on a subset of products (a real buyer wouldn't have bid on everything).
const BID_STATUS_STYLE = {
  Placed: { label: "Placed", className: "status-placed" },
  Rejected: { label: "Rejected", className: "status-rejected" },
  Completed: { label: "Completed", className: "status-completed" },
  Approved: { label: "Approved", className: "status-approved" },
};

// Shared by the desktop card (LastBidNote) and the mobile compact strip
// (MobileLastBidStrip) so both surfaces agree on the same mock bid per product.
function getLastBidInfo(product) {
  const h = hashProductId(product.id + "-lastbid");

  // ~55% of products show no prior bid at all.
  if (h % 20 < 11) return null;

  const statuses = ["Placed", "Rejected", "Completed", "Approved"];
  const status = statuses[(h >>> 4) % statuses.length];
  const style = BID_STATUS_STYLE[status];
  const isFinalized = status === "Approved" || status === "Completed";
  const priceLabel = isFinalized ? "Final" : "Bid";

  const variant = product.variants[h % product.variants.length];
  const basePrice = variant.sellingPrice || 100;
  const bidFactor = 0.82 + ((h >>> 6) % 12) / 100;
  const bidAmount = Math.round(basePrice * bidFactor);
  const daysAgo = 1 + ((h >>> 8) % 12);

  return { status, style, priceLabel, bidAmount, daysAgo };
}

// Minimal one-liner - same treatment as MobileLastBidStrip/ActivityNote,
// not a bordered card. Status carries its color as plain text, not a pill.
function LastBidNote({ product }) {
  const info = getLastBidInfo(product);
  if (!info) return null;
  const { status, style, priceLabel, bidAmount, daysAgo } = info;

  return (
    <div className="last-bid-note">
      <Gavel size={13} strokeWidth={2} className="last-bid-icon" />
      <span className="last-bid-text tabular">
        Last bid ${bidAmount.toLocaleString()} <span className="last-bid-price-label">({priceLabel})</span> · {daysAgo}d ago
      </span>
      <span className={"last-bid-status " + style.className}>{style.label}</span>
      {status === "Approved" && <button className="last-bid-cta">Checkout →</button>}
    </div>
  );
}

// Compact single-line version for the mobile detail page - the full bordered
// card takes too much vertical space above the fold on a phone.
function MobileLastBidStrip({ product }) {
  const info = getLastBidInfo(product);
  if (!info) return null;
  const { status, style, priceLabel, bidAmount, daysAgo } = info;

  return (
    <div className={"mobile-last-bid-strip last-bid-edge-" + style.className}>
      <span className="mobile-last-bid-main">
        <span className="mobile-last-bid-label">
          <Gavel size={12} strokeWidth={2.25} />
          Last bid
        </span>
        <span className="mobile-last-bid-text tabular">
          ${bidAmount.toLocaleString()} ({priceLabel}) · {daysAgo}d ago
        </span>
      </span>
      {status === "Approved" && <button className="mobile-last-bid-cta">Checkout →</button>}
      <span className={"status-pill " + style.className}>{style.label}</span>
    </div>
  );
}

// Parses whatever recognizable spec keywords exist in a product title.
// Deliberately conservative - a whitelist of known tokens, not a loose
// catch-all regex - so it never invents a spec that isn't really there.
// A field is simply absent (not shown as N/A) if nothing matches.
function parseSpecsFromTitle(title) {
  const tokens = title.split(/\s+/);
  const clean = (t) => t.replace(/[.,]/g, "");
  const networkTokens = ["2G", "3G", "4G", "5G"];
  const wifiTokens = ["Wifi", "WiFi", "Wi-Fi"];
  const simTokens = { DS: "Dual SIM", SS: "Single SIM" };
  const marketTokens = ["GCC", "Arabic", "Global"];
  const keywordSet = new Set([...networkTokens, ...wifiTokens, ...Object.keys(simTokens)]);

  let network = null;
  let sim = null;
  let model = null;

  for (const raw of tokens) {
    const t = clean(raw);
    if (networkTokens.includes(t)) network = t;
    else if (wifiTokens.includes(t)) network = "Wi-Fi";
    if (simTokens[t]) sim = simTokens[t];
  }

  const marketMatches = tokens.map(clean).filter((t) => marketTokens.includes(t));
  const market = marketMatches.length ? marketMatches.join(" · ") : null;

  for (let i = 0; i < tokens.length; i++) {
    if (keywordSet.has(clean(tokens[i]))) {
      if (i > 0) model = clean(tokens[i - 1]);
      break;
    }
  }

  const btMatch = title.match(/\bBT\s*V?[\d.]+\b/i) || title.match(/\bBluetooth\s+[\d.]+\b/i);
  const connectivity = btMatch ? btMatch[0].trim() : null;

  const wattMatch = title.match(/\b\d+\s?W\b/);
  const wattage = wattMatch ? wattMatch[0].replace(/\s/g, "") : null;

  const ipMatch = title.match(/\bIPX?\d{1,2}\b/i);
  const waterResistance = ipMatch ? ipMatch[0].toUpperCase() : null;

  return { model, network, sim, market, connectivity, wattage, waterResistance };
}

function SpecSheet({ product }) {
  const specs = parseSpecsFromTitle(product.name);
  const rows = [
    { label: "Model", value: specs.model },
    { label: "Network", value: specs.network },
    { label: "SIM", value: specs.sim },
    { label: "Market", value: specs.market },
    { label: "Connectivity", value: specs.connectivity },
    { label: "Power", value: specs.wattage },
    { label: "Water Resistance", value: specs.waterResistance },
  ].filter((r) => r.value);

  if (rows.length === 0) return null;

  return (
    <div className="spec-sheet">
      {rows.map((r) => (
        <div className="spec-row" key={r.label}>
          <span className="spec-label">{r.label}</span>
          <span className="spec-value">{r.value}</span>
        </div>
      ))}
    </div>
  );
}

// Dedupes product.image + every variant.image into one gallery list, shared
// by DetailHero (desktop) and MobileHero (mobile full-bleed carousel).
function getProductImages(product) {
  const seen = new Set();
  const list = [];
  if (product.image && !seen.has(product.image)) {
    seen.add(product.image);
    list.push(product.image);
  }
  product.variants.forEach((v) => {
    if (v.image && !seen.has(v.image)) {
      seen.add(v.image);
      list.push(v.image);
    }
  });
  return list;
}

function DetailHero({ product }) {
  const images = useMemo(() => getProductImages(product), [product]);

  const [activeIndex, setActiveIndex] = useState(0);
  const [failed, setFailed] = useState({});
  useEffect(() => {
    setActiveIndex(0);
    setFailed({});
  }, [product.id]);
  const Icon = CATEGORY_ICON[product.category] || LayoutGrid;

  const safeIndex = activeIndex < images.length ? activeIndex : 0;
  const activeSrc = images[safeIndex];
  const showPhoto = activeSrc && !failed[safeIndex];

  return (
    <div className="detail-hero-block">
      <div className="detail-hero-wrap">
        <div className="detail-hero">
          {showPhoto ? (
            <img
              src={activeSrc}
              alt=""
              className="detail-hero-img"
              onError={() => setFailed((f) => ({ ...f, [safeIndex]: true }))}
            />
          ) : (
            <Icon size={48} strokeWidth={1.2} />
          )}
        </div>
      </div>
      {images.length > 1 && (
        <div className="detail-gallery">
          {images.map((src, i) => (
            <button
              key={i}
              className={"detail-gallery-thumb" + (i === safeIndex ? " is-active" : "")}
              onClick={() => setActiveIndex(i)}
            >
              {!failed[i] ? (
                <img
                  src={src}
                  alt=""
                  onError={() => setFailed((f) => ({ ...f, [i]: true }))}
                />
              ) : (
                <Icon size={16} strokeWidth={1.4} />
              )}
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

// Price-forward header for Product Detail (desktop) - price is the primary
// element read first, the product photo is demoted to a small identifying
// thumbnail beside it (reusing DetailHero's existing image-loading/fallback
// logic via a CSS-only compact wrapper, not a rewrite), with a sparkline
// showing recent trend inline.
function ProductPriceHeader({ product }) {
  const priceTrend = useMemo(() => getPriceTrend(product), [product]);
  const directionClass = priceTrend?.direction === "up" ? " pd-price-up" : priceTrend?.direction === "down" ? " pd-price-down" : "";
  const hasStorage = productHasStorage(product);
  const hasColor = productHasColor(product);
  // Nothing to differentiate rows by - one variant, no storage/color to
  // list. Repeating the product name as a "label" here would just restate
  // the title above, so this collapses to a single bigger price line
  // instead of a sparse one-item list.
  const isSingleVariant = product.variants.length === 1 && !hasStorage && !hasColor;
  const singleVariant = isSingleVariant ? product.variants[0] : null;
  const singleTrend = singleVariant ? getVariantPriceTrend(product, singleVariant) : null;
  const singleDirectionClass = singleTrend?.direction === "up" ? " pd-price-up" : singleTrend?.direction === "down" ? " pd-price-down" : "";

  return (
    <div className={"pd-price-card" + (isSingleVariant ? " is-hero" : "")}>
      {/* Title lives inside the card, same pattern as Order Book's header -
         a card is one visual unit with its own heading, not a floating
         label plus a separate box. */}
      <div className="pd-price-card-title">Reference Price</div>
      <div className="pd-price-card-body">
      <div className="pd-price-list">
        {isSingleVariant ? (
          <span className={"pd-price-hero tabular" + singleDirectionClass}>
            {singleTrend?.direction === "up" && <TrendingUp size={18} strokeWidth={2.5} className="pd-price-arrow" />}
            {singleTrend?.direction === "down" && <TrendingDown size={18} strokeWidth={2.5} className="pd-price-arrow" />}
            {singleVariant.sellingPrice ? `$${singleVariant.sellingPrice.toLocaleString()}` : "—"}
          </span>
        ) : (
          /* Equal-weight grid, not one hero number - variants can price
             differently, so no single item is singled out as "the" price.
             Each item gets its own real trend/color - variants can
             genuinely move independently, unlike the collective average
             used for the chart. Side-by-side instead of stacked so
             variants can be compared at a glance (fastest path to "which
             one's cheapest"), not just scanned top-to-bottom. */
          <div className="pd-price-grid">
            {product.variants.map((v, i) => {
              // Color only earns a place in the label if it actually
              // correlates with a different price somewhere - otherwise
              // "· Silver" implies color is a pricing factor when it isn't.
              // Two ways that can be true: every variant in the product is
              // priced the same regardless of storage or color (the S26
              // Ultra case - $1,250 across all three, so color is a
              // non-factor everywhere, not just within one storage tier);
              // or, narrower, multiple colors share one storage at an
              // identical price even though the product overall does vary.
              const allVariantsSamePrice = product.variants.every((v2) => v2.sellingPrice === product.variants[0].sellingPrice);
              const sameStorageSiblings = hasStorage ? product.variants.filter((v2) => v2.storage === v.storage) : [];
              const colorRedundantWithinStorage = sameStorageSiblings.length > 1 && sameStorageSiblings.every((v2) => v2.sellingPrice === sameStorageSiblings[0].sellingPrice);
              const colorIsRedundant = hasStorage && (allVariantsSamePrice || colorRedundantWithinStorage);
              const label = [hasStorage && v.storage, hasColor && !colorIsRedundant && v.color].filter(Boolean).join(" · ") || product.name;
              const vTrend = getVariantPriceTrend(product, v);
              const vDirectionClass = vTrend?.direction === "up" ? " pd-price-up" : vTrend?.direction === "down" ? " pd-price-down" : "";
              return (
                <div className="pd-price-pair" key={i}>
                  <div className="pd-price-row-label">{label}</div>
                  <div className={"pd-price-row-value tabular" + vDirectionClass}>
                    {vTrend?.direction === "up" && <TrendingUp size={14} strokeWidth={2.5} className="pd-price-arrow" />}
                    {vTrend?.direction === "down" && <TrendingDown size={14} strokeWidth={2.5} className="pd-price-arrow" />}
                    {v.sellingPrice ? `$${v.sellingPrice.toLocaleString()}` : "—"}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* Aggregate delta lives with the chart it explains, not the label -
          they're the same number expressed two ways (figure + shape). */}
      {priceTrend ? (
        <div className="pd-sparkline-block">
          <div className={"pd-trend-badge tabular" + directionClass}>
            {priceTrend.direction === "up" && <TrendingUp size={13} strokeWidth={2.5} />}
            {priceTrend.direction === "down" && <TrendingDown size={13} strokeWidth={2.5} />}
            {priceTrend.change >= 0 ? "+" : "−"}{Math.abs(priceTrend.changePct).toFixed(1)}%
          </div>
          <Sparkline trend={priceTrend.trend} direction={priceTrend.direction} />
          <div className="pd-price-caption">Avg price trend · illustrative</div>
        </div>
      ) : (
        <div className="pd-price-empty">No trend data yet</div>
      )}
      </div>
    </div>
  );
}

// Always-visible strip - no expand/collapse. Wraps onto additional rows
// rather than scrolling so the full watchlist stays visible at once.
function WatchlistChip({ product, onSelect, onToggleWatchlist }) {
  const priceTrend = useMemo(() => getPriceTrend(product), [product]);
  const directionClass = priceTrend?.direction === "up" ? " pd-price-up" : priceTrend?.direction === "down" ? " pd-price-down" : "";
  const stock = getStockStatus(product);
  const cover = getCoverImage(product);
  const Icon = CATEGORY_ICON[product.category] || LayoutGrid;
  const [imgFailed, setImgFailed] = useState(false);
  const showPhoto = cover && !imgFailed;
  return (
    <button className="wl-chip" onClick={onSelect} title={product.name}>
      <div className={"wl-chip-thumb" + (showPhoto ? " has-photo" : "")}>
        {showPhoto ? <img src={cover} alt="" onError={() => setImgFailed(true)} /> : <Icon size={14} strokeWidth={1.6} />}
      </div>
      <span className="wl-chip-name">{product.name}</span>
      {priceTrend && (
        <span className={"wl-chip-price tabular" + directionClass}>
          {priceTrend.direction === "up" && <TrendingUp size={11} strokeWidth={2.5} />}
          {priceTrend.direction === "down" && <TrendingDown size={11} strokeWidth={2.5} />}
          ${priceTrend.current.toLocaleString()}
        </span>
      )}
      {stock === "out" && <span className="wl-chip-badge">Out of Stock</span>}
      <span
        className="wl-chip-remove"
        role="button"
        tabIndex={-1}
        onClick={(e) => {
          e.stopPropagation();
          onToggleWatchlist(product.id);
        }}
      >
        <X size={12} strokeWidth={2.25} />
      </span>
    </button>
  );
}

function WatchlistStrip({ products, onSelect, onToggleWatchlist }) {
  return (
    <div className="wl-strip">
      <div className="wl-strip-head">
        <span className="wl-strip-title">Watchlist{products.length > 0 ? ` (${products.length})` : ""}</span>
      </div>
      {products.length === 0 ? (
        <div className="wl-strip-empty">
          <Star size={14} strokeWidth={1.9} className="wl-empty-icon" />
          <span>No saved products yet — star items to track price and stock here.</span>
        </div>
      ) : (
        <div className="wl-strip-chips">
          {products.map((p) => (
            <WatchlistChip key={p.id} product={p} onSelect={() => onSelect(p.id)} onToggleWatchlist={onToggleWatchlist} />
          ))}
        </div>
      )}
    </div>
  );
}

function VariantRow({ variant, onAdd, showStorage, showColor, gridTemplate, isLast }) {
  const [qty, setQty] = useState("");
  const [price, setPrice] = useState("");
  const [swatchFailed, setSwatchFailed] = useState(false);
  // No disabled state on Add - it always looks ready. Tapping it with
  // empty fields shows exactly what's missing instead of doing nothing,
  // which is more legible to this audience than an abstract "greyed out
  // until valid" state (and sidesteps ever looking like another input).
  const [qtyError, setQtyError] = useState(false);
  const [priceError, setPriceError] = useState(false);

  const handleAdd = () => {
    const qtyValid = Number(qty) > 0;
    const priceValid = Number(price) > 0;
    if (!qtyValid || !priceValid) {
      setQtyError(!qtyValid);
      setPriceError(!priceValid);
      return;
    }
    onAdd({ storage: variant.storage, color: variant.color, qty: Number(qty), price: Number(price) });
    setQty("");
    setPrice("");
    setQtyError(false);
    setPriceError(false);
  };

  return (
    <div className={"vrow" + (isLast ? " vrow-last" : "")} style={{ gridTemplateColumns: gridTemplate }}>
      {showStorage && <div className="vrow-cell vrow-storage">{variant.storage}</div>}
      {showColor && (
        <div className="vrow-cell vrow-color">
          {variant.image && !swatchFailed && (
            <img src={variant.image} alt="" className="vrow-color-swatch" onError={() => setSwatchFailed(true)} />
          )}
          {variant.color}
        </div>
      )}
      <div className="vrow-cell">
        <div className="vrow-field-control">
          <input
            className={"vinput" + (qtyError ? " has-error" : "")}
            type="number"
            min="0"
            placeholder="0"
            value={qty}
            onChange={(e) => {
              setQty(e.target.value);
              setQtyError(false);
            }}
          />
          {qtyError && <span className="vinput-error">Enter quantity</span>}
        </div>
      </div>
      <div className="vrow-cell">
        <div className="vrow-field-control">
          <div className="vinput-price-wrap">
            <span className="vinput-currency">$</span>
            <input
              className={"vinput vinput-price" + (priceError ? " has-error" : "")}
              type="number"
              min="0"
              placeholder="0.00"
              value={price}
              onChange={(e) => {
                setPrice(e.target.value);
                setPriceError(false);
              }}
            />
          </div>
          {priceError && <span className="vinput-error">Enter price</span>}
        </div>
      </div>
      <div className="vrow-cell vrow-add">
        <button className="addbtn is-ready" onClick={handleAdd}>
          <Plus size={13} strokeWidth={2.25} />
          Add
        </button>
      </div>
    </div>
  );
}

