// Mobile equivalent of VariantRow - a table row doesn't work at this width,
// so each storage x color combo becomes its own expandable card with its
// own inline bid form, collapsed by default to avoid a wall of open forms.
function VariantCard({ variant, onAdd, showStorage, showColor, defaultExpanded, scrollContainerRef, footerHeight }) {
  const [expanded, setExpanded] = useState(!!defaultExpanded);
  const [qty, setQty] = useState("");
  const [price, setPrice] = useState("");
  const [swatchFailed, setSwatchFailed] = useState(false);
  const [qtyError, setQtyError] = useState(false);
  const [priceError, setPriceError] = useState(false);
  const cardRef = useRef(null);
  const didMountRef = useRef(false);

  const handleAdd = () => {
    const qtyValid = Number(qty) > 0;
    const priceValid = Number(price) > 0;
    if (!qtyValid || !priceValid) {
      setQtyError(!qtyValid);
      setPriceError(!priceValid);
      return;
    }
    onAdd({ storage: variant.storage, color: variant.color, qty: Number(qty), price: Number(price), variantImage: variant.image });
    setQty("");
    setPrice("");
    setQtyError(false);
    setPriceError(false);
  };

  const toggleExpanded = () => setExpanded((e) => !e);

  // Auto-scroll once the expanded form has actually committed to the DOM
  // (useEffect runs after paint, so cardRef's height already reflects the
  // form) - skips the initial mount so the card that starts pre-expanded
  // (already in view near the top) doesn't trigger a pointless scroll.
  useEffect(() => {
    if (!didMountRef.current) {
      didMountRef.current = true;
      return;
    }
    if (expanded) {
      scrollCardIntoView(cardRef.current, scrollContainerRef?.current, footerHeight || 0);
    }
  }, [expanded]);

  const title = [showStorage && variant.storage, showColor && variant.color].filter(Boolean).join(" · ");

  return (
    <div className={"vcard" + (expanded ? " is-expanded" : "")} ref={cardRef}>
      <button className="vcard-head" onClick={toggleExpanded}>
        <div className="vcard-head-main">
          {showColor && variant.image && !swatchFailed && (
            <img src={variant.image} alt="" className="vcard-swatch" onError={() => setSwatchFailed(true)} />
          )}
          <span className="vcard-title">{title}</span>
        </div>
        {/* No price here - it's redundant with the Reference Price section
            above, same separation of concerns as the desktop bid table. */}
        <ChevronRight size={15} strokeWidth={1.75} className={"vcard-chevron" + (expanded ? " is-open" : "")} />
      </button>
      {expanded && (
        <div className="vcard-form">
          <div className="vcard-field">
            <span className="vcard-field-label">Bid Qty</span>
            <div className="vcard-field-control">
              <input
                className={"vinput" + (qtyError ? " has-error" : "")}
                type="number"
                min="0"
                placeholder="0"
                value={qty}
                onChange={(e) => {
                  setQty(e.target.value);
                  setQtyError(false);
                }}
              />
              {qtyError && <span className="vinput-error">Enter quantity</span>}
            </div>
          </div>
          <div className="vcard-field">
            <span className="vcard-field-label">Target Price</span>
            <div className="vcard-field-control">
            <div className="vinput-price-wrap">
              <span className="vinput-currency">$</span>
              <input
                className={"vinput vinput-price" + (priceError ? " has-error" : "")}
                type="number"
                min="0"
                placeholder="0.00"
                value={price}
                onChange={(e) => {
                  setPrice(e.target.value);
                  setPriceError(false);
                }}
              />
            </div>
            {priceError && <span className="vinput-error">Enter price</span>}
            </div>
          </div>
          <button className="addbtn vcard-addbtn is-ready" onClick={handleAdd}>
            <Plus size={13} strokeWidth={2.25} />
            Add
          </button>
        </div>
      )}
    </div>
  );
}

// Full-bleed swipeable gallery for the mobile detail page - the boxed
// hero + thumbnail rail from DetailHero (desktop) doesn't fit at this width.
function MobileHero({ product }) {
  const images = useMemo(() => getProductImages(product), [product]);
  const [activeIndex, setActiveIndex] = useState(0);
  const [failed, setFailed] = useState({});
  const scrollRef = useRef(null);
  useEffect(() => {
    setActiveIndex(0);
    setFailed({});
    if (scrollRef.current) scrollRef.current.scrollLeft = 0;
  }, [product.id]);
  const Icon = CATEGORY_ICON[product.category] || LayoutGrid;

  const handleScroll = () => {
    const el = scrollRef.current;
    if (!el || !el.clientWidth) return;
    setActiveIndex(Math.round(el.scrollLeft / el.clientWidth));
  };

  if (images.length === 0) {
    return (
      <div className="mobile-hero">
        <div className="mobile-hero-fallback">
          <Icon size={48} strokeWidth={1.2} />
        </div>
      </div>
    );
  }

  return (
    <div className="mobile-hero">
      <div className="mobile-hero-scroll" ref={scrollRef} onScroll={handleScroll}>
        {images.map((src, i) =>
          !failed[i] ? (
            <img
              key={i}
              src={src}
              alt=""
              className="mobile-hero-img"
              onError={() => setFailed((f) => ({ ...f, [i]: true }))}
            />
          ) : (
            <div className="mobile-hero-fallback mobile-hero-img" key={i}>
              <Icon size={48} strokeWidth={1.2} />
            </div>
          )
        )}
      </div>
      {images.length > 1 && (
        <div className="mobile-hero-dots">
          {images.map((_, i) => (
            <span key={i} className={"mobile-hero-dot" + (i === activeIndex ? " is-active" : "")} />
          ))}
        </div>
      )}
    </div>
  );
}

// No real storage/color choice to make (e.g. Nokia feature phones) - skip
